import React from "react";

export default function NutritionInfo() {
  const bg =
    "https://images.unsplash.com/photo-1512621776951-a57141f2eefd?auto=format&fit=crop&w=1600&q=80";

  const cards = [
    {
      title: "Calories & Energy Balance",
      desc: "Understand how calories fuel your body and support daily activity.",
      img: "https://images.unsplash.com/photo-1566855582667-22dca89e146e?auto=format&fit=crop&w=800&q=80",
    },
    {
      title: "Macronutrient Breakdown",
      desc: "Learn how proteins, carbs and fats contribute to overall health.",
      img: "https://images.unsplash.com/photo-1543352634-09316b1c5f9b?auto=format&fit=crop&w=800&q=80",
    },
    {
      title: "Micronutrient Essentials",
      desc: "Discover why vitamins and minerals are vital for body functions.",
      img: "https://images.unsplash.com/photo-1518977676601-b53f82aba655?auto=format&fit=crop&w=800&q=80",
    },
  ];

  return (
    <div className="relative w-full min-h-screen">

      {/* BACKGROUND IMAGE (BLURRED) */}
      <div
        className="absolute inset-0 bg-cover bg-center filter blur-xl opacity-70"
        style={{ backgroundImage: `url(${bg})` }}
      ></div>

      {/* OVERLAY TO DARKEN A BIT */}
      <div className="absolute inset-0 bg-white/40"></div>

      {/* FOREGROUND CONTENT */}
      <div className="relative z-10 px-6 py-16 flex justify-center">
        <div className="max-w-6xl w-full">

          {/* TITLE */}
          <h1 className="text-3xl md:text-4xl font-semibold text-slate-900 text-center mb-12 drop-shadow-md">
            Nutrition Information
          </h1>

          {/* CARDS */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {cards.map((c, i) => (
              <div
                key={i}
                className="bg-white rounded-2xl shadow-xl overflow-hidden border hover:shadow-2xl transition"
              >
                <img
                  src={c.img}
                  alt={c.title}
                  className="w-full h-48 object-cover"
                />

                <div className="px-6 py-5">
                  <h3 className="text-lg text-emerald-600 font-semibold mb-2">
                    {c.title}
                  </h3>
                  <p className="text-slate-600 text-sm leading-relaxed">
                    {c.desc}
                  </p>
                </div>
              </div>
            ))}
          </div>

          <p className="mt-12 text-center text-sm text-slate-700">
            © 2025 MealPlanner — Nutrition Overview
          </p>
        </div>
      </div>
    </div>
  );
}
